func (v UserValue) IsNull() bool {
	return v.state == attr.ValueStateNull
}

func (v UserValue) IsUnknown() bool {
	return v.state == attr.ValueStateUnknown
}

func (v UserValue) String() string {
	return "UserValue"
}

func (v UserValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	attributeTypes := map[string]attr.Type{
		"display_name":    basetypes.StringType{},
		"email":           basetypes.StringType{},
		"first_name":      basetypes.StringType{},
		"id":              basetypes.StringType{},
		"job_title":       basetypes.StringType{},
		"language":        basetypes.StringType{},
		"last_name":       basetypes.StringType{},
		"organization_id": basetypes.StringType{},
		"phone":           basetypes.StringType{},
		"phone_extension": basetypes.StringType{},
		"role_id":         basetypes.StringType{},
		"status":          basetypes.StringType{},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"display_name":    v.DisplayName,
			"email":           v.Email,
			"first_name":      v.FirstName,
			"id":              v.Id,
			"job_title":       v.JobTitle,
			"language":        v.Language,
			"last_name":       v.LastName,
			"organization_id": v.OrganizationId,
			"phone":           v.Phone,
			"phone_extension": v.PhoneExtension,
			"role_id":         v.RoleId,
			"status":          v.Status,
		})

	return objVal, diags
}

func (v UserValue) Equal(o attr.Value) bool {
	other, ok := o.(UserValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.DisplayName.Equal(other.DisplayName) {
		return false
	}

	if !v.Email.Equal(other.Email) {
		return false
	}

	if !v.FirstName.Equal(other.FirstName) {
		return false
	}

	if !v.Id.Equal(other.Id) {
		return false
	}

	if !v.JobTitle.Equal(other.JobTitle) {
		return false
	}

	if !v.Language.Equal(other.Language) {
		return false
	}

	if !v.LastName.Equal(other.LastName) {
		return false
	}

	if !v.OrganizationId.Equal(other.OrganizationId) {
		return false
	}

	if !v.Phone.Equal(other.Phone) {
		return false
	}

	if !v.PhoneExtension.Equal(other.PhoneExtension) {
		return false
	}

	if !v.RoleId.Equal(other.RoleId) {
		return false
	}

	if !v.Status.Equal(other.Status) {
		return false
	}

	return true
}

